    72→            FutureCallback<Void> cb = new FutureCallback<>();
    73→            herder.healthCheck(cb);
    74→
    75→            long timeoutNs = TimeUnit.MILLISECONDS.toNanos(requestTimeout.healthCheckTimeoutMs());
    76→            long deadlineNs = timeoutNs + time.nanoseconds();
    77→            time.waitForFuture(cb, deadlineNs);
    78→
    79→            statusCode = Response.Status.OK.getStatusCode();
